  # Group triples by subject to allow multiple predicates for the same entity
      subject_map = {}
      for t in triples:
          subject_map.setdefault(t.subject, []).append((t.predicate, t.object))

      sentences = []
      for subj, pred_objs in subject_map.items():
          # Build individual predicate phrases for this subject
          parts = []
          for pred, obj in pred_objs:
              phrase = predicate_map.get(pred, lambda s, o: f"{s} {pred} {o}")(subj, obj)
              parts.append(phrase)
          # Combine the parts for the same subject
          if len(parts) == 1:
              sentences.append(parts[0])
          else:
              *head, tail = parts
              combined = ", ".join(head) + ", and " + tail
              sentences.append(combined)

      # Combine different subject clauses into a single fluent paragraph
      if not sentences:
          return ""
      if len(sentences) == 1:
          return sentences[0] + "."
      # Join each subject clause with a space, ensuring each ends with a period
      return " ".join(s.rstrip('.') + "." for s in sentences)
